import {
  TagGroup as BaseTagGroup,
  Tag as BaseTag,
  TagList as BaseTagList,
} from './BaseTagsGroup';
import { ComponentPropsWithoutRef } from 'react';
import { WithDataId } from '@/types/withDataId';
export type TagProps = ComponentPropsWithoutRef<typeof BaseTag> & WithDataId;
export type TagGroupProps = ComponentPropsWithoutRef<typeof BaseTagGroup>;
export function TagsGroup({ children, ...props }: TagGroupProps) {
  return <BaseTagGroup {...props}>{children}</BaseTagGroup>;
}

TagsGroup.TagList = BaseTagList;
TagsGroup.Tag = BaseTag;
